import React, { useState, useCallback, useEffect, useRef } from 'react';
import { ControlPanel } from './components/ControlPanel';
import { OutputDisplay } from './components/OutputDisplay';
import { LoadSessionModal } from './components/LoadSessionModal';
import { SupportAgent } from './components/SupportAgent';
import type { OutputDisplayHandle } from './components/OutputDisplay';
import type { ControlPanelState, ResultState, SavedSession, AppMode } from './types';
import { runReasoning, runFactAnalysis } from './services/geminiService';

const App: React.FC = () => {
  const [problem, setProblem] = useState('');
  const [mode, setMode] = useState<AppMode>('reasoning');
  const [controlState, setControlState] = useState<ControlPanelState>({
    depth: 'Lite',
    speed: 'Fast',
    creativity: 'Low',
    web: true,
    images: false,
    metaFix: true,
    selfReflection: false,
    framework: 'Causal Spine',
    paypalLink: '',
  });

  const [result, setResult] = useState<ResultState | null>(null);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [apiKeyError, setApiKeyError] = useState<string | null>(null);
  const [savedSessions, setSavedSessions] = useState<SavedSession[]>([]);
  const [isLoadModalOpen, setIsLoadModalOpen] = useState(false);
  const [paymentStatus, setPaymentStatus] = useState<'none' | 'pending'>('none');
  const outputDisplayRef = useRef<OutputDisplayHandle>(null);

  useEffect(() => {
    if (!process.env.API_KEY) {
      setApiKeyError("API key not found. Please configure your API key to use the application.");
    }
    // Load sessions from localStorage on initial render
    try {
      const storedSessions = localStorage.getItem('reasoning_sessions');
      if (storedSessions) {
        setSavedSessions(JSON.parse(storedSessions));
      }

      const storedPaypal = localStorage.getItem('paypal_link');
      if (storedPaypal) {
        setControlState(prev => ({ ...prev, paypalLink: storedPaypal }));
      }
    } catch (e) {
      console.error("Failed to load sessions from localStorage", e);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('paypal_link', controlState.paypalLink);
  }, [controlState.paypalLink]);

  const handleSaveSession = useCallback(() => {
    if (!problem.trim()) {
        alert("Please enter a problem statement before saving.");
        return;
    }

    const sessionName = problem.substring(0, 50) + (problem.length > 50 ? '...' : '');

    const newSession: SavedSession = {
      id: Date.now(),
      name: sessionName,
      timestamp: new Date().toISOString(),
      problem,
      controlState,
      result,
      mode,
    };

    const updatedSessions = [newSession, ...savedSessions];
    setSavedSessions(updatedSessions);
    localStorage.setItem('reasoning_sessions', JSON.stringify(updatedSessions));
  }, [problem, controlState, result, savedSessions, mode]);

  const handleLoadSession = useCallback((session: SavedSession) => {
      setProblem(session.problem);
      setControlState(session.controlState);
      setResult(session.result);
      setMode(session.mode ?? 'reasoning');
      setIsLoadModalOpen(false);
  }, []);

  const handleDeleteSession = useCallback((sessionId: number) => {
      const updatedSessions = savedSessions.filter(s => s.id !== sessionId);
      setSavedSessions(updatedSessions);
      localStorage.setItem('reasoning_sessions', JSON.stringify(updatedSessions));
  }, [savedSessions]);

  const handleRun = useCallback(async () => {
    if (apiKeyError) return;
    const input = problem.trim();
    if (!input) {
      setError(mode === 'reasoning' ? 'Please enter a problem statement.' : 'Please enter at least one fact.');
      return;
    }
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      let response;
      if (mode === 'reasoning') {
          response = await runReasoning(input, controlState);
      } else {
          response = await runFactAnalysis(input);
      }
      setResult(response);
    } catch (e) {
      console.error(e);
      setError(e instanceof Error ? e.message : 'An unexpected error occurred.');
    } finally {
      setLoading(false);
    }
  }, [problem, controlState, apiKeyError, mode]);

  const handlePay = useCallback(() => {
    const link = controlState.paypalLink.trim();
    if (!link) {
      alert("Please configure a PayPal.me link in Admin Settings.");
      return;
    }

    // BUILD URL: https://www.paypal.me/[CLEANED_HANDLE]/120
    const cleanedHandle = link.replace(/\+/g, '').replace(/\.paypal/g, '').replace(/^https?:\/\/(www\.)?paypal\.me\//, '');
    const payUrl = `https://www.paypal.me/${cleanedHandle}/120`;

    window.open(payUrl, '_blank');
    setPaymentStatus('pending');
  }, [controlState.paypalLink]);

  return (
    <div className="flex flex-col md:flex-row min-h-screen md:h-screen md:overflow-hidden font-sans">
      <ControlPanel
        state={controlState}
        setState={setControlState}
        problem={problem}
        setProblem={setProblem}
        onRun={handleRun}
        onSave={handleSaveSession}
        onLoad={() => setIsLoadModalOpen(true)}
        isLoading={loading}
        isApiKeyMissing={!!apiKeyError}
        mode={mode}
        setMode={setMode}
      />

      <main className="flex-grow flex flex-col md:h-full md:overflow-hidden bg-gray-900 relative">
        {apiKeyError && (
          <div className="bg-red-900/80 border-b border-red-500 text-red-200 px-4 py-2 text-center text-sm">
            {apiKeyError}
          </div>
        )}

        <div className="flex-grow md:overflow-y-auto p-4 md:p-8">
            <SupportAgent 
              status={paymentStatus}
              onPay={handlePay}
            />

            <OutputDisplay 
                ref={outputDisplayRef} 
                result={result} 
                isLoading={loading} 
                error={error} 
            />
        </div>

        {result && !loading && !error && (
            <div className="fixed md:absolute bottom-6 right-8 flex space-x-2 z-10">
                <button 
                    onClick={() => outputDisplayRef.current?.exportToPNG()}
                    className="bg-gray-700 hover:bg-gray-600 text-white text-xs px-3 py-2 rounded shadow transition-colors"
                >
                    Export PNG
                </button>
                 <button 
                    onClick={() => outputDisplayRef.current?.exportToPDF()}
                    className="bg-gray-700 hover:bg-gray-600 text-white text-xs px-3 py-2 rounded shadow transition-colors"
                >
                    Export PDF
                </button>
            </div>
        )}
      </main>

      <LoadSessionModal
        isOpen={isLoadModalOpen}
        sessions={savedSessions}
        onClose={() => setIsLoadModalOpen(false)}
        onLoad={handleLoadSession}
        onDelete={handleDeleteSession}
      />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import type { ControlPanelState, Framework, AppMode, Depth, Speed, Creativity } from '../types';
import { FRAMEWORKS } from '../constants';
import { CogIcon, WebIcon, ImageIcon, CheckCircleIcon, BrainCircuitIcon, WandSparklesIcon, SaveIcon, FolderOpenIcon, TrashIcon } from './ui/icons';

interface ControlPanelProps {
  state: ControlPanelState;
  setState: React.Dispatch<React.SetStateAction<ControlPanelState>>;
  problem: string;
  setProblem: React.Dispatch<React.SetStateAction<string>>;
  onRun: () => void;
  onSave: () => void;
  onLoad: () => void;
  isLoading: boolean;
  isApiKeyMissing: boolean;
  mode: AppMode;
  setMode: React.Dispatch<React.SetStateAction<AppMode>>;
}

const ToggleButton: React.FC<{
  label: string;
  icon: React.ReactNode;
  isActive: boolean;
  onClick: () => void;
  disabled?: boolean;
  title?: string;
}> = ({ label, icon, isActive, onClick, disabled = false, title }) => (
  <button
    type="button"
    onClick={onClick}
    disabled={disabled}
    title={title}
    className={`flex items-center space-x-2 w-full p-2 rounded-md text-sm transition-colors ${
      isActive ? 'bg-accent-500 text-white' : 'bg-gray-700 hover:bg-gray-600'
    } ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
  >
    {icon}
    <span>{label}</span>
  </button>
);

const TabButton: React.FC<{
  children: React.ReactNode;
  active: boolean;
  onClick: () => void;
}> = ({ children, active, onClick }) => (
  <button
    onClick={onClick}
    className={`px-4 py-2 text-sm font-medium rounded-t-md transition-colors focus:outline-none w-1/2 ${
      active
        ? 'bg-gray-900 text-accent-400'
        : 'text-gray-400 hover:bg-gray-700'
    }`}
  >
    {children}
  </button>
);

const SegmentedControl: React.FC<{
  label: string;
  options: string[];
  value: string;
  onChange: (value: any) => void;
  disabled: boolean;
}> = ({ label, options, value, onChange, disabled }) => (
  <div>
    <label className="block text-sm font-medium text-gray-300 mb-2 text-center">{label}</label>
    <div className="flex rounded-md shadow-sm bg-gray-700">
      {options.map((option, idx) => (
        <button
          key={option}
          onClick={() => onChange(option)}
          disabled={disabled}
          className={`px-3 py-1 text-sm flex-1 transition-colors disabled:opacity-50
            ${value === option ? 'bg-accent-500 text-white' : 'hover:bg-gray-600'}
            ${idx === 0 ? 'rounded-l-md' : ''}
            ${idx === options.length - 1 ? 'rounded-r-md' : ''}
          `}
        >
          {option}
        </button>
      ))}
    </div>
  </div>
);


export const ControlPanel: React.FC<ControlPanelProps> = ({
  state,
  setState,
  problem,
  setProblem,
  onRun,
  onSave,
  onLoad,
  isLoading,
  isApiKeyMissing,
  mode,
  setMode,
}) => {
  const handleStateChange = <T extends keyof ControlPanelState>(field: T, value: ControlPanelState[T]) => {
    setState(prevState => ({ ...prevState, [field]: value }));
  };

  const selectedFrameworkInfo = FRAMEWORKS.find(f => f.name === state.framework);

  return (
    <aside className="w-full md:w-96 bg-gray-800 p-4 md:p-6 flex flex-col border-b md:border-b-0 md:border-r border-gray-700 md:h-full md:overflow-y-auto shrink-0">
      <header className="mb-4">
        <h1 className="text-2xl font-bold text-accent-400">Reasoning Control Panel</h1>
        <p className="text-sm text-gray-400">Tune Gemini's reasoning process.</p>
      </header>

      <div className="flex border-b border-gray-700">
        <TabButton active={mode === 'reasoning'} onClick={() => setMode('reasoning')}>
          Reasoning
        </TabButton>
        <TabButton active={mode === 'facts'} onClick={() => setMode('facts')}>
          Facts
        </TabButton>
      </div>

      <div className="mt-4 flex-grow flex flex-col">
        <label htmlFor="problem-input" className="text-sm font-medium text-gray-300 mb-2">
          {mode === 'reasoning' ? 'Problem Statement' : 'Enter Facts (one per line)'}
        </label>
        <textarea
          id="problem-input"
          value={problem}
          onChange={(e) => setProblem(e.target.value)}
          placeholder={mode === 'reasoning' ? 'Describe the complex problem you want to solve...' : 'e.g., The suspect was seen near the library at 3 PM.\nThe library card was found at the scene.'}
          className="w-full flex-grow p-3 bg-gray-900 border border-gray-600 rounded-md focus:ring-2 focus:ring-accent-500 focus:outline-none resize-none min-h-[150px]"
          rows={mode === 'reasoning' ? 6 : 10}
          disabled={isLoading || isApiKeyMissing}
        />
      </div>

      <div className="flex items-center space-x-2 my-4">
        <button
          onClick={onRun}
          disabled={isLoading || isApiKeyMissing || !problem.trim()}
          className="flex-grow inline-flex items-center justify-center px-4 py-2 text-base font-medium rounded-md shadow-sm text-white bg-accent-600 hover:bg-accent-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-accent-500 disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {isLoading ? (
            <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
          ) : mode === 'reasoning' ? <BrainCircuitIcon className="w-5 h-5 mr-2" /> : <WandSparklesIcon className="w-5 h-5 mr-2" />}
          Run {mode === 'reasoning' ? 'Reasoning' : 'Analysis'}
        </button>
        <button onClick={onSave} title="Save Session" className="p-2 bg-gray-700 hover:bg-gray-600 rounded-md disabled:opacity-50" disabled={isLoading || !problem.trim()}><SaveIcon className="w-5 h-5" /></button>
        <button onClick={onLoad} title="Load Session" className="p-2 bg-gray-700 hover:bg-gray-600 rounded-md disabled:opacity-50" disabled={isLoading}><FolderOpenIcon className="w-5 h-5" /></button>
      </div>

      {mode === 'reasoning' && (
        <div className="space-y-4">
          <div className="grid grid-cols-3 gap-2">
            <SegmentedControl label="Depth" options={['Lite', 'Pro']} value={state.depth} onChange={(v) => handleStateChange('depth', v as Depth)} disabled={isLoading || isApiKeyMissing} />
            <SegmentedControl label="Speed" options={['Fast', 'Balanced', 'Careful']} value={state.speed} onChange={(v) => handleStateChange('speed', v as Speed)} disabled={isLoading || isApiKeyMissing} />
            <SegmentedControl label="Creativity" options={['Low', 'Medium', 'High']} value={state.creativity} onChange={(v) => handleStateChange('creativity', v as Creativity)} disabled={isLoading || isApiKeyMissing} />
          </div>

          <div className="grid grid-cols-2 gap-2">
            <ToggleButton label="Web Search" icon={<WebIcon className="w-4 h-4" />} isActive={state.web} onClick={() => handleStateChange('web', !state.web)} disabled={isLoading || isApiKeyMissing} title="Enable Google Search for up-to-date information." />
            <ToggleButton label="Generate Image" icon={<ImageIcon className="w-4 h-4" />} isActive={state.images} onClick={() => handleStateChange('images', !state.images)} disabled={isLoading || isApiKeyMissing} title="Allow the model to generate a relevant image." />
            <ToggleButton label="Meta-Fix" icon={<CheckCircleIcon className="w-4 h-4" />} isActive={state.metaFix} onClick={() => handleStateChange('metaFix', !state.metaFix)} disabled={isLoading || isApiKeyMissing} title="Ask the model to critique its own reasoning." />
            <ToggleButton label="Self-Reflect" icon={<BrainCircuitIcon className="w-4 h-4" />} isActive={state.selfReflection} onClick={() => handleStateChange('selfReflection', !state.selfReflection)} disabled={isLoading || isApiKeyMissing} title="Ask the model for a confidence score on its answer." />
          </div>

          <div>
            <label htmlFor="framework-select" className="text-sm font-medium text-gray-300 mb-2 flex items-center">
              <CogIcon className="w-4 h-4 mr-2" />
              Reasoning Framework
