            <select
              id="framework-select"
              value={state.framework}
              onChange={(e) => handleStateChange('framework', e.target.value as Framework)}
              disabled={isLoading || isApiKeyMissing}
              className="w-full p-2 bg-gray-700 border border-gray-600 rounded-md focus:ring-2 focus:ring-accent-500 focus:outline-none"
