            {selectedFrameworkInfo && state.framework !== 'None' && (
              <div className="mt-2 p-3 bg-gray-900/50 rounded-md text-xs text-gray-400 border border-gray-700">
                <p className="font-bold mb-1 text-gray-300">Description:</p>
                <p className="mb-2">{selectedFrameworkInfo.description}</p>
                <p className="font-bold mb-1 text-gray-300">Primary Drivers:</p>
